module adder_32bit
(
    input [32:1] A,
    input [32:1] B,
    output [32:1] S,
    output C32
);
    wire [3:0] G;
    wire [3:0] P;
    wire [3:0] C;
    wire [3:0] S_temp;

    gen_prop gp0(.A(A[0]), .B(B[0]), .G(G[0]), .P(P[0]));
    gen_prop gp1(.A(A[1]), .B(B[1]), .G(G[1]), .P(P[1]));
    gen_prop gp2(.A(A[2]), .B(B[2]), .G(G[2]), .P(P[2]));
    gen_prop gp3(.A(A[3]), .B(B[3]), .G(G[3]), .P(P[3]));

    carry_lookahead_logic cll0(.G(G[3:0]), .P(P[3:0]), .Cin(Cin), .C(C[3:0]), .Cout(Cout));

    assign S_temp[0] = A[0] ^ B[0] ^ Cin;
    assign S_temp[1] = A[1] ^ B[1] ^ C[0];
    assign S_temp[2] = A[2] ^ B[2] ^ C[1];
    assign S_temp[3] = A[3] ^ B[3] ^ C[2];
    assign S[3:0] = S_temp[3:0];
    assign S[7:4] = S_temp[3:0];
    assign S[11:8] = S_temp[3:0];
    assign S[15:12] = S_temp[3:0];
    assign S[19:16] = S_temp[3:0];
    assign S[23:20] = S_temp[3:0];
    assign S[27:24] = S_temp[3:0];
    assign S[31:28] = S_temp[3:0];
    assign S[32] = Cout;
endmodule
